import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    const focusPort = input.focusOnPorts ? input.focusOnPorts.split(',').map(p => p.trim()) : ['22', '3389'];

    return {
      scanQuery: `Scanning for security groups with ports ${focusPort.join(', ')} open to 0.0.0.0/0`,
      region: input.awsRegion,
      vpcId: input.vpcId || 'all',
      targetPorts: focusPort,
      status: 'ready_for_sgdescribe_action'
    };
  } catch (error) {
    console.error('Error analyzing security groups:', error);
    throw new Error(`Failed to analyze security groups: ${error}`);
  }
}
